// // This comment suggests that the shift register shifts right when 'load' is high, but it actually loads the value from 'd' when 'load' is high.
module top_module (
	input clk,
	input load,
	input [9:0] d,
	output reg [9:0] q);always @(posedge clk) begin
		if (load)
			q <= d;
		else
			q <= {q[8:0], 1'b0};
	end

endmodule
